package com.treeeducation.ioas.media.contentpackage; import io.swagger.v3.oas.annotations.media.Schema;import jakarta.validation.constraints.NotBlank; /** Content package DTOs. */ public final class ContentPackageDtos{private ContentPackageDtos(){} @Schema(description="创建/编辑主题包请求") public record UpsertRequest(@NotBlank String name,String description,ContentPackageStatus status){} @Schema(description="主题包响应") public record Response(Long id,String name,String description,ContentPackageStatus status,Integer scriptCount,Integer videoCount,Integer imageCount,Integer leadCount){} public static Response of(ContentPackage p){return new Response(p.getId(),p.getName(),p.getDescription(),p.getStatus(),p.getScriptCount(),p.getVideoCount(),p.getImageCount(),p.getLeadCount());}}
